# Parse the response
python3 -c "
import json, base64, re

with open('/tmp/nano_correct.json') as f:
    data = json.load(f)

content = data.get('choices', [{}])[0].get('message', {}).get('content', '')

if isinstance(content, str):
    # Check for base64 image in markdown format
    match = re.search(r'data:image/[^;]+;base64,([A-Za-z0-9+/=]+)', content)
    if match:
        img = base64.b64decode(match.group(1))
        path = '~/.openclaw/workspace/nano-banana-banner.png'
        with open(path, 'wb') as f:
            f.write(img)
        print(f'✅ NANO BANANA IMAGE SAVED! {path} ({len(img)} bytes)')
    elif content.strip():
        print(f'Text response (first 500 chars): {content[:500]}')
    else:
        print('Empty content')
        print(f'Full response keys: {list(data.keys())}')
        print(f'Choices: {json.dumps(data.get(\"choices\", []), indent=2)[:500]}')
elif isinstance(content, list):
    for i, part in enumerate(content):
        if isinstance(part, dict):
            ptype = part.get('type', 'unknown')
            if 'image' in ptype or 'image_url' in str(part):
                url = part.get('image_url', {}).get('url', '') or part.get('url', '')
                if 'base64' in url:
                    b64 = url.split(',', 1)[1]
                    img = base64.b64decode(b64)
                    path = f'~/.openclaw/workspace/nano-banana-{i}.png'
                    with open(path, 'wb') as f:
                        f.write(img)
                    print(f'✅ Saved {path} ({len(img)} bytes)')
                else:
                    print(f'Image URL: {url[:200]}')
            else:
                print(f'Part {i}: type={ptype}, text={str(part.get(\"text\",\"\"))[:200]}')
" 2>&1

